#include<bits/stdc++.h>
using namespace std;
long long n,k,num[15];
string num1;
int main() {
	cin >> n;
	while (n--) {
		cin >>k>>num1;
		long long ans=0;
		for (long long i=0; i<num1.size(); i++) {
			if (!(num1[i]>='0'&&num1[i]<='9')) {
				num[i]=num1[i]-'A'+10;
			} else {
				num[i]=num1[i]-'0';
			}
			ans=ans*k+num[i];
		}
		cout<<ans<<"\n";
	}
	return 0;
}
